import java.util.*;
import java.util.stream.*;

public class StreamPipeline {

    record Person(String name, int age, String city) {}

    public static void main(String[] args) {
        List<Person> people = List.of(
            new Person("Alice",  30, "Delhi"),
            new Person("Bob",    17, "Mumbai"),
            new Person("Carol",  25, "Delhi"),
            new Person("Dave",   15, "Chennai"),
            new Person("Eve",    28, "Mumbai")
        );

        // Pipeline: source → filter → map → sorted → collect
        List<String> adults = people.stream()          // 1. source
            .filter(p -> p.age() >= 18)                // 2. keep adults only
            .map(Person::name)                         // 3. extract name
            .sorted()                                  // 4. alphabetical
            .collect(Collectors.toList());             // 5. terminal — triggers execution

        System.out.println(adults); // [Alice, Carol, Eve]

        // count — terminal that returns long
        long delhiCount = people.stream()
            .filter(p -> p.city().equals("Delhi"))
            .count();
        System.out.println("Delhi residents: " + delhiCount); // 2

        // findFirst — short-circuits: stops at first match
        Optional<Person> youngest = people.stream()
            .filter(p -> p.age() >= 18)
            .min(Comparator.comparingInt(Person::age));
        youngest.ifPresent(p -> System.out.println("Youngest adult: " + p.name())); // Carol
    }
}

import java.util.*;
import java.util.stream.*;

public class CollectorsDemo {

    record Product(String name, String category, double price) {}

    public static void main(String[] args) {
        List<Product> products = List.of(
            new Product("Apple",    "Fruit",       1.5),
            new Product("Banana",   "Fruit",       0.8),
            new Product("Carrot",   "Vegetable",   0.6),
            new Product("Laptop",   "Electronics", 999.0),
            new Product("Phone",    "Electronics", 599.0),
            new Product("Broccoli", "Vegetable",   1.2)
        );

        // groupingBy — Map<category, List<Product>>
        Map<String, List<Product>> byCategory = products.stream()
            .collect(Collectors.groupingBy(Product::category));
        System.out.println(byCategory.get("Fruit").size()); // 2

        // groupingBy + downstream collector — Map<category, count>
        Map<String, Long> countByCategory = products.stream()
            .collect(Collectors.groupingBy(Product::category, Collectors.counting()));
        System.out.println(countByCategory); // {Fruit=2, Vegetable=2, Electronics=2}

        // groupingBy + averagingDouble — average price per category
        Map<String, Double> avgPrice = products.stream()
            .collect(Collectors.groupingBy(Product::category,
                     Collectors.averagingDouble(Product::price)));
        System.out.println(avgPrice.get("Electronics")); // 799.0

        // partitioningBy — Map<Boolean, List> (two groups: match / no-match)
        Map<Boolean, List<Product>> expensive = products.stream()
            .collect(Collectors.partitioningBy(p -> p.price() > 10));
        System.out.println(expensive.get(true).size());  // 2 (Laptop, Phone)
        System.out.println(expensive.get(false).size()); // 4

        // joining — concatenate strings
        String names = products.stream()
            .map(Product::name)
            .collect(Collectors.joining(", ", "[", "]"));
        System.out.println(names); // [Apple, Banana, Carrot, Laptop, Phone, Broccoli]

        // toMap — Map<name, price>
        Map<String, Double> priceMap = products.stream()
            .collect(Collectors.toMap(Product::name, Product::price));
        System.out.println(priceMap.get("Laptop")); // 999.0
    }
}

import java.util.*;
import java.util.function.*;
import java.util.stream.*;

public class FunctionalInterfaces {

    public static void main(String[] args) {

        // Predicate<T> — boolean test(T t)
        Predicate<String> notBlank   = s  -> !s.isBlank();
        Predicate<String> longEnough = s  -> s.length() >= 5;
        Predicate<String> valid      = notBlank.and(longEnough); // compose

        System.out.println(valid.test("hello"));  // true
        System.out.println(valid.test(""));        // false
        System.out.println(valid.test("hi"));      // false (too short)

        // Function<T,R> — R apply(T t)
        Function<String, Integer> length   = String::length;
        Function<Integer, String> classify = n -> n > 5 ? "long" : "short";
        Function<String, String>  pipeline = length.andThen(classify); // compose

        System.out.println(pipeline.apply("hello"));      // short (5)
        System.out.println(pipeline.apply("programming")); // long (11)

        // Consumer<T> — void accept(T t) — side-effect only
        Consumer<String> print   = System.out::println;
        Consumer<String> upper   = s -> System.out.println(s.toUpperCase());
        Consumer<String> both    = print.andThen(upper); // both run

        both.accept("java"); // java \n JAVA

        // Supplier<T> — T get() — no input, produces value
        Supplier<List<String>> listFactory = ArrayList::new;
        List<String> a = listFactory.get();
        List<String> b = listFactory.get(); // two independent empty lists
        System.out.println(a == b); // false — fresh instances

        // BiFunction<T,U,R>, UnaryOperator<T>, BinaryOperator<T>
        BiFunction<String, Integer, String> repeat = (s, n) -> s.repeat(n);
        System.out.println(repeat.apply("ab", 3)); // ababab

        UnaryOperator<String>  trim   = String::trim;
        BinaryOperator<String> concat = (a2, b2) -> a2 + b2;
        System.out.println(trim.apply("  hi  "));         // hi
        System.out.println(concat.apply("Hello", " World")); // Hello World
    }
}

import java.util.*;
import java.util.stream.*;

public class MethodRefsAndFlatMap {

    static class Order {
        String id;
        List<String> items;
        Order(String id, String... items) {
            this.id = id;
            this.items = List.of(items);
        }
    }

    static String process(String s) { return s.trim().toUpperCase(); }

    public static void main(String[] args) {

        // ── Method references (4 kinds) ──────────────────────────────────
        // 1. Static method: ClassName::staticMethod
        List<String> words = List.of(" hello ", " world ", " java ");
        words.stream().map(MethodRefsAndFlatMap::process).forEach(System.out::println);
        // HELLO / WORLD / JAVA

        // 2. Instance method on arbitrary instance: ClassName::instanceMethod
        List<String> names = List.of("Alice", "bob", "CAROL");
        names.stream().map(String::toLowerCase).forEach(System.out::println);
        // alice / bob / carol

        // 3. Instance method on specific instance: instance::method
        String prefix = "Hello, ";
        names.stream().map(prefix::concat).forEach(System.out::println);
        // Hello, Alice / Hello, bob / Hello, CAROL

        // 4. Constructor reference: ClassName::new
        List<Integer> nums = List.of(1, 2, 3);
        List<StringBuilder> builders = nums.stream()
            .map(Object::toString)
            .map(StringBuilder::new)  // String → new StringBuilder(String)
            .collect(Collectors.toList());
        System.out.println(builders); // [1, 2, 3]

        // ── flatMap — flatten Stream<List<T>> → Stream<T> ────────────────
        List<Order> orders = List.of(
            new Order("O1", "Apple", "Banana"),
            new Order("O2", "Carrot"),
            new Order("O3", "Date", "Elderberry", "Fig")
        );

        // WITHOUT flatMap: Stream<List<String>> — nested
        // orders.stream().map(o -> o.items) → Stream<List<String>>

        // WITH flatMap: Stream<String> — flattened
        List<String> allItems = orders.stream()
            .flatMap(o -> o.items.stream()) // each List<String> → Stream<String>
            .distinct()
            .sorted()
            .collect(Collectors.toList());
        System.out.println(allItems);
        // [Apple, Banana, Carrot, Date, Elderberry, Fig]
    }
}

import java.util.*;
import java.util.concurrent.*;
import java.util.stream.*;
import java.util.function.*;

public class ParallelAndCustomCollector {

    // Custom Collector: accumulate into a StringJoiner with stats
    static Collector<String, StringJoiner, String> toCSV(String delimiter) {
        return Collector.of(
            () -> new StringJoiner(delimiter),          // supplier: creates accumulator
            StringJoiner::add,                          // accumulator: adds element
            StringJoiner::merge,                        // combiner: merges two (for parallel)
            StringJoiner::toString                      // finisher: converts to result
        );
    }

    public static void main(String[] args) throws Exception {

        // ── Parallel stream — uses ForkJoinPool ──────────────────────────
        List<Integer> numbers = IntStream.rangeClosed(1, 1_000_000)
            .boxed().collect(Collectors.toList());

        long t1 = System.currentTimeMillis();
        long sumSeq = numbers.stream()
            .mapToLong(Integer::longValue).sum(); // sequential
        long t2 = System.currentTimeMillis();

        long sumPar = numbers.parallelStream()
            .mapToLong(Integer::longValue).sum(); // parallel
        long t3 = System.currentTimeMillis();

        System.out.println("Sequential: " + (t2-t1) + "ms, sum=" + sumSeq);
        System.out.println("Parallel:   " + (t3-t2) + "ms, sum=" + sumPar);
        System.out.println("Results match: " + (sumSeq == sumPar)); // true

        // ── Parallel pitfall: stateful operations ─────────────────────────
        List<Integer> unsafeResult = new ArrayList<>();
        // DON'T DO THIS — ArrayList is not thread-safe:
        // numbers.parallelStream().forEach(unsafeResult::add);
        // DO THIS — collect into thread-safe result:
        List<Integer> safeResult = numbers.parallelStream()
            .filter(n -> n % 2 == 0)
            .collect(Collectors.toList()); // Collectors handle thread safety internally
        System.out.println("Even count: " + safeResult.size()); // 500000

        // ── Custom Collector ──────────────────────────────────────────────
        List<String> fruits = List.of("Apple", "Banana", "Cherry", "Date");
        String csv = fruits.stream().collect(toCSV(", "));
        System.out.println(csv); // Apple, Banana, Cherry, Date
    }
}

