import java.util.*;
import java.util.stream.*;

public class Q6 {
    public static long countDistinctWords(String sentence) {
        if (sentence == null || sentence.isBlank()) return 0;
        return Arrays.stream(sentence.split("\\s+"))
                     .map(w -> w.replaceAll("[^a-zA-Z]", "").toLowerCase())
                     .filter(w -> !w.isEmpty())
                     .distinct()
                     .count();
    }
    public static void main(String[] args) {
        System.out.println(countDistinctWords("Hello world hello Java world")); // 3
        System.out.println(countDistinctWords("To be, or not to be"));         // 4
    }
}

