import java.util.*;
import java.util.stream.*;
import java.util.function.*;

public class Q9 {
    public static Map<String, Long> wordFrequency(List<String> words) {
        return words.stream()
                    .collect(Collectors.groupingBy(Function.identity(), Collectors.counting()));
    }
    public static String mostFrequent(List<String> words) {
        return words.stream()
                    .collect(Collectors.groupingBy(Function.identity(), Collectors.counting()))
                    .entrySet().stream()
                    .max(Map.Entry.comparingByValue())
                    .map(Map.Entry::getKey)
                    .orElse("");
    }
    public static void main(String[] args) {
        var words = List.of("apple","banana","apple","cherry","banana","apple");
        System.out.println(wordFrequency(words));
        System.out.println(mostFrequent(words)); // apple
    }
}

