import java.util.*;
import java.util.function.*;
import java.util.stream.*;

public class Q13 {
    record Product(String name, String category, double price) {}

    static class ProductFilter {
        private Predicate<Product> predicate = p -> true;

        public ProductFilter withMinPrice(double min) {
            predicate = predicate.and(p -> p.price() >= min); return this;
        }
        public ProductFilter withMaxPrice(double max) {
            predicate = predicate.and(p -> p.price() <= max); return this;
        }
        public ProductFilter withCategory(String cat) {
            predicate = predicate.and(p -> p.category().equalsIgnoreCase(cat)); return this;
        }
        public ProductFilter withNameContains(String text) {
            predicate = predicate.and(p -> p.name().toLowerCase().contains(text.toLowerCase())); return this;
        }
        public List<Product> apply(List<Product> products) {
            return products.stream().filter(predicate).collect(Collectors.toList());
        }
    }

    public static void main(String[] args) {
        var products = List.of(
            new Product("Apple","Fruit",1.5),
            new Product("Laptop","Electronics",999.0),
            new Product("Phone","Electronics",499.0),
            new Product("Banana","Fruit",0.8));
        new ProductFilter()
            .withCategory("Electronics")
            .withMaxPrice(600)
            .apply(products)
            .forEach(p -> System.out.println(p.name())); // Phone
    }
}

