import java.util.*;
import java.util.concurrent.ThreadLocalRandom;
import java.util.stream.*;

public class Q16 {
    public static List<Long> fibonacci(int n) {
        return Stream.iterate(new long[]{0,1}, f -> new long[]{f[1], f[0]+f[1]})
                     .limit(n)
                     .map(f -> f[0])
                     .collect(Collectors.toList());
    }
    public static List<Integer> randomAbove50(int count) {
        return Stream.generate(() -> ThreadLocalRandom.current().nextInt(1, 101))
                     .filter(n -> n > 50)
                     .limit(count)
                     .collect(Collectors.toList());
    }
    public static List<Integer> powersOfTwo() {
        return Stream.iterate(1, n -> n * 2)
                     .takeWhile(n -> n <= 1024)
                     .collect(Collectors.toList());
    }
    public static void main(String[] args) {
        System.out.println(fibonacci(8));
        System.out.println(randomAbove50(3).size());
        System.out.println(powersOfTwo());
    }
}

