import java.util.*;
import java.util.stream.*;

public class Q17 {
    public static Map<String, Long> wordCount(List<String> sentences) {
        return sentences.parallelStream()
            .flatMap(s -> Arrays.stream(s.split("\\s+")))
            .map(w -> w.replaceAll("[^a-zA-Z]", "").toLowerCase())
            .filter(w -> !w.isEmpty())
            .collect(Collectors.groupingByConcurrent(
                w -> w, Collectors.counting()));
    }

    public static void main(String[] args) {
        var sentences = List.of(
            "To be or not to be",
            "That is the question",
            "To be is to exist");
        var counts = wordCount(sentences);
        System.out.println(counts.get("to")); // 4
        System.out.println(counts.get("be")); // 3
        System.out.println(counts.get("is")); // 2
    }
}

