import java.util.*;
import java.util.function.*;
import java.util.stream.*;

public class Q20 {
    static class QueryBuilder<T> {
        private Stream<T> stream;
        QueryBuilder(List<T> source) { this.stream = source.stream(); }
        private QueryBuilder(Stream<T> s) { this.stream = s; }

        public QueryBuilder<T> filter(Predicate<T> pred)   { stream = stream.filter(pred);   return this; }
        public QueryBuilder<T> sortBy(Comparator<T> cmp)   { stream = stream.sorted(cmp);    return this; }
        public QueryBuilder<T> limit(int n)                { stream = stream.limit(n);       return this; }
        public QueryBuilder<T> skip(int n)                 { stream = stream.skip(n);        return this; }
        public QueryBuilder<T> distinct()                  { stream = stream.distinct();     return this; }
        public <R> QueryBuilder<R> map(Function<T,R> fn)   { return new QueryBuilder<>(stream.map(fn)); }
        public List<T> toList()  { return stream.collect(Collectors.toList()); }
        public long    count()   { return stream.count(); }
    }

    public static void main(String[] args) {
        var data = List.of(5,3,8,1,9,2,5,3,7,4);
        System.out.println(
            new QueryBuilder<>(data)
                .filter(n -> n > 3).distinct()
                .sortBy(Comparator.naturalOrder()).limit(4)
                .toList()); // [4, 5, 7, 8]
        System.out.println(
            new QueryBuilder<>(data).filter(n -> n%2==0).count()); // 3
    }
}
